#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN=1e5+5;
vector<int> t[MAXN];               
ll n,a[MAXN],f[MAXN],ans = 0;     
//tree-DP
void dfs(int u, int fa) 
{
    f[u] = a[u];           
    for (int s : t[u]) 
    {   
        if (s == fa) continue; 
        dfs(s, u);       
        if (f[s] > 0) f[u] += f[s];  
    }
    ans = max(ans, f[u]); 
    return;
}
int main(void)
{
    n=read();
    for(int i=1;i<=n;++i)
    {
        a[i]=read();
    }
    for(int i=1,u,v;i<n;++i)
    {
        u=read(),v=read();
        t[u].push_back(v);
        t[v].push_back(u);
    }
    dfs(1,-1);
    write(ans);
    return false;
}
